Source code in <code>src/holodeck/cli/commands/deploy.py</code> <pre><code>def _load_agent_and_deployment(
    agent_config: str,
) -&gt; tuple[Agent, DeploymentConfig, Path]:
    from holodeck.config.loader import ConfigLoader

    loader = ConfigLoader()
    agent = loader.load_agent_yaml(agent_config)

    if not agent.deployment:
        raise ConfigError(
            field="deployment",
            message="No 'deployment' section found in agent configuration",
        )

    return agent, agent.deployment, Path(agent_config).resolve()
